// ═══════════════════════════════════════════════════════════════════════
const WALLETS = [
    { id: "metamask", name: "MetaMask", icon: "🦊", color: "#E2761B", desc: "Portefeuille Web3 populaire", chain: "Multi-chain" },
    { id: "walletconnect", name: "WalletConnect", icon: "🔗", color: "#3B99FC", desc: "Connexion universelle", chain: "Multi-chain" },
    { id: "kingest", name: "Kingest Wallet", icon: "👑", color: "#6BA5FF", desc: "Wallet intégré Kingest", chain: "Tous réseaux" },
    { id: "coinbase", name: "Coinbase Wallet", icon: "🔵", color: "#0052FF", desc: "Par Coinbase", chain: "Multi-chain" },
    { id: "phantom", name: "Phantom", icon: "👻", color: "#AB9FF2", desc: "Solana & Multi-chain", chain: "Solana · ETH" },
    { id: "trust", name: "Trust Wallet", icon: "🛡️", color: "#3375BB", desc: "Par Binance", chain: "Multi-chain" }
];

const CHAINS = [
    { id: "ethereum", name: "Ethereum", sym: "ETH", icon: "⟠", color: "#627EEA", tvl: "58.2B" },
    { id: "arbitrum", name: "Arbitrum", sym: "ARB", icon: "🔵", color: "#28A0F0", tvl: "12.8B" },
    { id: "polygon", name: "Polygon", sym: "MATIC", icon: "🟣", color: "#8247E5", tvl: "1.2B" },
    { id: "bsc", name: "BNB Chain", sym: "BNB", icon: "🟡", color: "#F3BA2F", tvl: "5.4B" },
    { id: "solana", name: "Solana", sym: "SOL", icon: "◎", color: "#9945FF", tvl: "4.1B" },
    { id: "base", name: "Base", sym: "ETH", icon: "🔷", color: "#0052FF", tvl: "7.5B" },
    { id: "hyperliquid", name: "Hyperliquid", sym: "HYPE", icon: "⚡", color: "#50E3C2", tvl: "3.2B" }
];

function WalletModal({ onClose, onConnect }) {
    const [step, setStep] = useState("select");
    const [selWallet, setSelWallet] = useState(null);
    const [chain, setChain] = useState(CHAINS[0]);
    const [connecting, setConnecting] = useState(false);

    const doConnect = (w) => {
        setSelWallet(w);
        setConnecting(true);
        setTimeout(() => {
            setConnecting(false);
            setStep("chain");
        }, 1500);
    };

    const finalConnect = () => {
        const addr = "0x" + Array.from({length: 8}, () => Math.floor(Math.random()*16).toString(16)).join("") + "..." + Array.from({length: 4}, () => Math.floor(Math.random()*16).toString(16)).join("");
        onConnect({ wallet: selWallet, chain, address: addr, balance: (Math.random() * 50000 + 5000).toFixed(2) });
        onClose();
    };

    return (
        <div style={{ position: "fixed", inset: 0, zIndex: 5000, display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(0,0,0,0.7)", backdropFilter: "blur(8px)", animation: "fadeIn 0.2s" }} onClick={onClose}>
            <div onClick={e => e.stopPropagation()} style={{ width: "440px", maxHeight: "85vh", borderRadius: "20px", background: "rgba(15,28,50,0.95)", border: "1px solid rgba(107,165,255,0.15)", boxShadow: "0 24px 80px rgba(0,0,0,0.5)", overflow: "auto" }}>
                <div style={{ padding: "24px 24px 0", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <div>
                        <div style={{ fontSize: "18px", fontWeight: 800, color: "#fff" }}>{step === "select" ? "🔗 Connecter Wallet" : "⛓️ Choisir Réseau"}</div>
                        <div style={{ fontSize: "12px", color: "rgba(255,255,255,0.5)", marginTop: "4px" }}>Trading décentralisé · Sans intermédiaire</div>
                    </div>
                    <button onClick={onClose} style={{ background: "rgba(255,255,255,0.06)", border: "none", color: "#fff", width: "32px", height: "32px", borderRadius: "50%", cursor: "pointer", fontSize: "16px" }}>✕</button>
                </div>

                {step === "select" && (
                    <div style={{ padding: "20px" }}>
                        <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
                            {WALLETS.map(w => (
                                <button key={w.id} onClick={() => doConnect(w)} style={{
                                    display: "flex", alignItems: "center", gap: "14px", padding: "16px", borderRadius: "14px",
                                    background: connecting && selWallet?.id === w.id ? `${w.color}15` : "rgba(255,255,255,0.03)",
                                    border: `1px solid ${connecting && selWallet?.id === w.id ? w.color + "44" : "rgba(255,255,255,0.06)"}`,
                                    cursor: "pointer", transition: "all 0.2s", width: "100%", textAlign: "left"
                                }}>
                                    <div style={{ width: "44px", height: "44px", borderRadius: "12px", background: `${w.color}18`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "22px", border: `1px solid ${w.color}25`, flexShrink: 0 }}>{w.icon}</div>
                                    <div style={{ flex: 1 }}>
                                        <div style={{ fontSize: "14px", fontWeight: 700, color: "#fff" }}>{w.name}</div>
                                        <div style={{ fontSize: "11px", color: "rgba(255,255,255,0.4)" }}>{w.desc} · {w.chain}</div>
                                    </div>
                                    {connecting && selWallet?.id === w.id ? (
                                        <div style={{ fontSize: "12px", color: w.color, fontWeight: 600 }}>Connexion...</div>
                                    ) : (
                                        <div style={{ fontSize: "18px", color: "rgba(255,255,255,0.2)" }}>›</div>
                                    )}
                                </button>
                            ))}
                        </div>
                        <div style={{ marginTop: "16px", padding: "12px", borderRadius: "10px", background: "rgba(107,165,255,0.06)", border: "1px solid rgba(107,165,255,0.1)" }}>
                            <div style={{ fontSize: "11px", color: "rgba(107,165,255,0.8)", fontWeight: 600 }}>🔒 Connexion sécurisée · Vos clés restent privées</div>
                        </div>
                    </div>
                )}

                {step === "chain" && (
                    <div style={{ padding: "20px" }}>
                        <div style={{ display: "flex", alignItems: "center", gap: "10px", padding: "12px", borderRadius: "10px", background: `${selWallet.color}10`, border: `1px solid ${selWallet.color}22`, marginBottom: "16px" }}>
                            <span style={{ fontSize: "20px" }}>{selWallet.icon}</span>
                            <div>
                                <div style={{ fontSize: "13px", fontWeight: 700, color: selWallet.color }}>{selWallet.name}</div>
                                <div style={{ fontSize: "10px", color: "rgba(255,255,255,0.4)" }}>Connecté ✓</div>
                            </div>
                        </div>
                        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "8px" }}>
                            {CHAINS.map(ch => (
                                <button key={ch.id} onClick={() => setChain(ch)} style={{
                                    padding: "14px", borderRadius: "12px", cursor: "pointer", transition: "all 0.2s", textAlign: "left",
                                    background: chain.id === ch.id ? `${ch.color}15` : "rgba(255,255,255,0.02)",
                                    border: `1px solid ${chain.id === ch.id ? ch.color + "55" : "rgba(255,255,255,0.05)"}`
                                }}>
                                    <div style={{ fontSize: "18px", marginBottom: "6px" }}>{ch.icon}</div>
                                    <div style={{ fontSize: "12px", fontWeight: 700, color: chain.id === ch.id ? ch.color : "#fff" }}>{ch.name}</div>
                                    <div style={{ fontSize: "10px", color: "rgba(255,255,255,0.35)" }}>TVL: ${ch.tvl}</div>
                                </button>
                            ))}
                        </div>
                        <button onClick={finalConnect} style={{
                            width: "100%", marginTop: "16px", padding: "14px", borderRadius: "12px", border: "none", cursor: "pointer",
                            background: "linear-gradient(135deg, #6BA5FF, #4A8AE8)", color: "#fff", fontSize: "14px", fontWeight: 700
                        }}>⚡ Connecter à {chain.name}</button>
                    </div>
                )}
            </div>
        </div>
    );
}


