function calcSpread(assetType, tier, amount) {
    const t = tier === "elite" ? "elite" : tier === "pro" ? "pro" : "standard";
    const rate = SPREAD_TABLE[assetType]?.[t] || 0.002;
    return amount * rate;
}

function calcOvernight(amount, leverage) {
    const rate = getOvernightRate(leverage);
    return amount * leverage * rate;
}

