// ── API Config ──
const LIVE_CONFIG = { FINNHUB_KEY: "d6nk53pr01qodk605ra0d6nk53pr01qodk605rag", COINGECKO_KEY: "", OER_KEY: "" };

// ── Safe Fetch avec timeout ──
async function _safeFetch(url, ms = 8000) {
    const ac = new AbortController();
    const t = setTimeout(() => ac.abort(), ms);
    try { const r = await fetch(url, { signal: ac.signal }); clearTimeout(t); if (r.status === 429) throw new Error("RATE_LIMIT"); if (!r.ok) throw new Error("HTTP_" + r.status); return await r.json(); }
    catch (e) { clearTimeout(t); throw e; }
}

// ── Fetch avec fallback multi-provider ──
async function _fetchFB(providers, sym, norm) {
    const now = Date.now();
    for (const p of providers) {
        if (p._off && now < p._offUntil) continue;
        try {
            const data = await _safeFetch(p.url(sym));
            p._off = false; p._errs = 0;
            return norm(p.id, data, sym);
        } catch (e) {
            if (e.message === "RATE_LIMIT") { p._off = true; p._offUntil = now + 60000; }
            p._errs = (p._errs || 0) + 1;
            if (p._errs > 5) { p._off = true; p._offUntil = now + 300000; }
        }
    }
    return null;
}

// ── CoinGecko ID Map ──
const _CGK = { BTC:"bitcoin",ETH:"ethereum",SOL:"solana",BNB:"binancecoin",XRP:"ripple",ADA:"cardano",DOGE:"dogecoin",AVAX:"avalanche-2",DOT:"polkadot",LINK:"chainlink",MATIC:"matic-network",UNI:"uniswap",SHIB:"shiba-inu",LTC:"litecoin",ATOM:"cosmos",FIL:"filecoin",APT:"aptos",NEAR:"near",OP:"optimism",ARB:"arbitrum",SUI:"sui",SEI:"sei-network",TIA:"celestia",INJ:"injective-protocol",RENDER:"render-token",FET:"fetch-ai",STX:"blockstack",RUNE:"thorchain" };

// ── Agent Status ──
const _AS = { idle:"idle", fetch:"fetching", ok:"success", err:"error" };

// ── Hook: Binance WebSocket (Crypto streaming) ──
function useBinanceWS(syms, on = true) {
    const [px, setPx] = useState({});
    const ws = useRef(null);
    useEffect(() => {
        if (!on || !syms.length) return;
        try {
            const streams = syms.map(s => s.toLowerCase() + "usdt@miniTicker").join("/");
            ws.current = new WebSocket("wss://stream.binance.com:9443/stream?streams=" + streams);
            ws.current.onmessage = (ev) => {
                const m = JSON.parse(ev.data);
                if (m.data) { const d = m.data, s = (d.s || "").replace("USDT", ""); if (s) setPx(p => ({ ...p, [s]: { price: +d.c, chg: +d.P } })); }
            };
            ws.current.onerror = () => {};
        } catch {}
        return () => { if (ws.current?.readyState === WebSocket.OPEN) ws.current.close(); };
    }, [syms.join(","), on]);
    return px;
}

// ── Hook: Agent Actions (Finnhub) ──
function useStockAgent(syms, iv = 30000) {
    const [data, setData] = useState({});
    const [st, setSt] = useState({ status: _AS.idle, last: null, fetches: 0, errs: 0, lat: 0 });
    useEffect(() => {
        if (!LIVE_CONFIG.FINNHUB_KEY || !syms.length) return;
        let on = true;
        const providers = [{ id: "finnhub", url: (s) => `/api/finnhub/quote?symbol=${s}&token=${LIVE_CONFIG.FINNHUB_KEY}` }];
        const norm = (id, d, s) => ({ sym: s, price: d.c || 0, chg: d.dp || 0, high: d.h, low: d.l, open: d.o });
        const go = async () => {
            setSt(s => ({ ...s, status: _AS.fetch }));
            const t0 = Date.now(); let ok = 0;
            for (const s of syms) {
                if (!on) break;
                const r = await _fetchFB(providers, s, norm);
                if (r) { setData(p => ({ ...p, [s]: r })); ok++; }
                await new Promise(r => setTimeout(r, 1100));
            }
            setSt(s => ({ ...s, status: ok > 0 ? _AS.ok : _AS.err, last: new Date().toLocaleTimeString("fr-FR"), fetches: s.fetches + 1, lat: Math.round((s.lat + Date.now() - t0) / 2) }));
        };
        go(); const t = setInterval(go, iv);
        return () => { on = false; clearInterval(t); };
    }, [syms.join(","), iv]);
    return { data, status: st };
}

// ── Hook: Agent Crypto (CoinGecko + Binance WS) ──
function useCryptoAgent(syms, iv = 60000) {
    const [data, setData] = useState({});
    const [st, setSt] = useState({ status: _AS.idle, last: null, fetches: 0, errs: 0, lat: 0 });
    const wsPrices = useBinanceWS(syms.slice(0, 20), true);
    useEffect(() => {
        if (!syms.length) return;
        let on = true;
        const go = async () => {
            setSt(s => ({ ...s, status: _AS.fetch }));
            const t0 = Date.now();
            const ids = syms.map(s => _CGK[s]).filter(Boolean).join(",");
            if (!ids) { setSt(s => ({ ...s, status: _AS.err })); return; }
            try {
                const raw = await _safeFetch(`/api/coingecko/simple/price?ids=${ids}&vs_currencies=usd&include_24hr_change=true&include_market_cap=true`);
                const map = {};
                for (const [id, info] of Object.entries(raw)) {
                    const sym = Object.entries(_CGK).find(([, v]) => v === id)?.[0];
                    if (sym) map[sym] = { sym, price: info.usd || 0, chg: +(info.usd_24h_change || 0).toFixed(2), mcap: info.usd_market_cap || 0 };
                }
                if (on) setData(p => ({ ...p, ...map }));
                setSt(s => ({ ...s, status: _AS.ok, last: new Date().toLocaleTimeString("fr-FR"), fetches: s.fetches + 1, lat: Math.round((s.lat + Date.now() - t0) / 2) }));
            } catch { setSt(s => ({ ...s, status: _AS.err, errs: s.errs + 1 })); }
        };
        go(); const t = setInterval(go, iv);
        return () => { on = false; clearInterval(t); };
    }, [syms.join(","), iv]);
    // Merge WS on top of REST
    const merged = useMemo(() => {
        const r = { ...data };
        for (const [s, w] of Object.entries(wsPrices)) { if (r[s]) r[s] = { ...r[s], price: w.price, chg: w.chg }; else r[s] = { sym: s, price: w.price, chg: w.chg }; }
        return r;
    }, [data, wsPrices]);
    return { data: merged, status: st };
}

// ── Hook: Agent Forex (Frankfurter) ──
function useForexAgent(iv = 300000) {
    const [data, setData] = useState({});
    const [st, setSt] = useState({ status: _AS.idle, last: null, fetches: 0, errs: 0, lat: 0 });
    useEffect(() => {
        let on = true;
        const go = async () => {
            setSt(s => ({ ...s, status: _AS.fetch }));
            const t0 = Date.now();
            try {
                const [usd, eur] = await Promise.all([
                    _safeFetch("/api/frankfurter/latest?base=USD"),
                    _safeFetch("/api/frankfurter/latest?base=EUR"),
                ]);
                const map = {};
                if (usd?.rates) Object.entries(usd.rates).forEach(([c, r]) => { map[`USD/${c}`] = { sym: `USD/${c}`, price: r }; });
                if (eur?.rates) Object.entries(eur.rates).forEach(([c, r]) => { map[`EUR/${c}`] = { sym: `EUR/${c}`, price: r }; });
                // Compute cross rates for common pairs
                if (usd?.rates?.EUR) map["EUR/USD"] = { sym: "EUR/USD", price: +(1 / usd.rates.EUR).toFixed(4) };
                if (usd?.rates?.GBP) map["GBP/USD"] = { sym: "GBP/USD", price: +(1 / usd.rates.GBP).toFixed(4) };
                if (usd?.rates?.JPY) map["USD/JPY"] = { sym: "USD/JPY", price: usd.rates.JPY };
                if (usd?.rates?.CHF) map["USD/CHF"] = { sym: "USD/CHF", price: usd.rates.CHF };
                if (usd?.rates?.CAD) map["USD/CAD"] = { sym: "USD/CAD", price: usd.rates.CAD };
                if (usd?.rates?.AUD) map["AUD/USD"] = { sym: "AUD/USD", price: +(1 / usd.rates.AUD).toFixed(4) };
                if (on) setData(p => ({ ...p, ...map }));
                setSt(s => ({ ...s, status: _AS.ok, last: new Date().toLocaleTimeString("fr-FR"), fetches: s.fetches + 1, lat: Math.round((s.lat + Date.now() - t0) / 2) }));
            } catch { setSt(s => ({ ...s, status: _AS.err, errs: s.errs + 1 })); }
        };
        go(); const t = setInterval(go, iv);
        return () => { on = false; clearInterval(t); };
    }, [iv]);
    return { data, status: st };
}

// ── Hook: Agent Commodités (gold-api.com) ──
function useCommodityAgent(iv = 60000) {
    const [data, setData] = useState({});
    const [st, setSt] = useState({ status: _AS.idle, last: null, fetches: 0, errs: 0, lat: 0 });
    useEffect(() => {
        let on = true;
        const metals = [["XAU","Or (Gold)","🥇"],["XAG","Argent (Silver)","🥈"],["XPT","Platine","⬜"],["XPD","Palladium","🔘"]];
        const go = async () => {
            setSt(s => ({ ...s, status: _AS.fetch }));
            const t0 = Date.now(); let ok = 0;
            for (const [sym, name, emoji] of metals) {
                if (!on) break;
                try {
                    const raw = await _safeFetch(`/api/goldapi/price/${sym}`);
                    if (raw?.price) { setData(p => ({ ...p, [`${sym}/USD`]: { sym: `${sym}/USD`, price: raw.price, chg: raw.chp || 0, name, emoji } })); ok++; }
                } catch {}
                await new Promise(r => setTimeout(r, 500));
            }
            // ETFs via Finnhub if key available
            if (LIVE_CONFIG.FINNHUB_KEY) {
                const etfs = [["USO","CL","Pétrole WTI","🛢️"],["UNG","NG","Gaz Naturel","🔥"],["WEAT","WHEAT","Blé","🌾"]];
                for (const [etf, sym, name, emoji] of etfs) {
                    if (!on) break;
                    try {
                        const raw = await _safeFetch(`https://finnhub.io/api/v1/quote?symbol=${etf}&token=${LIVE_CONFIG.FINNHUB_KEY}`);
                        if (raw?.c) { setData(p => ({ ...p, [sym]: { sym, price: raw.c, chg: raw.dp || 0, name, emoji } })); ok++; }
                    } catch {}
                    await new Promise(r => setTimeout(r, 1100));
                }
            }
            setSt(s => ({ ...s, status: ok > 0 ? _AS.ok : _AS.err, last: new Date().toLocaleTimeString("fr-FR"), fetches: s.fetches + 1, lat: Math.round((s.lat + Date.now() - t0) / 2) }));
        };
        go(); const t = setInterval(go, iv);
        return () => { on = false; clearInterval(t); };
    }, [iv]);
    return { data, status: st };
}

// ── HYBRID Live Hook: uses real API data when available, falls back to simulation ──
function useLive(initial, liveData = {}) {
    const [d, setD] = useState(initial);
    // Apply live data on top of simulated
    useEffect(() => {
        if (Object.keys(liveData).length === 0) return;
        setD(prev => {
            const next = [...prev];
            for (let i = 0; i < next.length; i++) {
                const sym = next[i].sym;
                const live = liveData[sym];
                if (live) {
                    next[i] = { ...next[i], price: live.price || next[i].price, chg: live.chg != null ? live.chg : next[i].chg };
                }
            }
            return next;
        });
    }, [liveData]);
    // Simulation fallback for assets without live data
    useEffect(() => {
        const iv = setInterval(() => {
            setD(p => {
                const next = [...p];
                const batchSize = Math.min(50, next.length);
                for (let b = 0; b < batchSize; b++) {
                    const i = Math.floor(Math.random() * next.length);
                    const a = next[i];
                    // Skip if this asset has live data
                    if (liveData[a.sym]) continue;
                    const v = a.price > 1000 ? 0.003 : a.price > 100 ? 0.005 : a.price > 1 ? 0.008 : 0.012;
                    const delta = a.price * v * (Math.random() - 0.48);
                    next[i] = { ...a, price: +Math.max(a.price * 0.9, a.price + delta).toFixed(a.price < 1 ? 4 : a.price < 10 ? 3 : 2), chg: +((delta / a.price) * 100).toFixed(2) };
                }
                return next;
            });
        }, 2500);
        return () => clearInterval(iv);
    }, [Object.keys(liveData).length]);
    return d;
}

// ── Mini Chart (eToro style) ──
function MiniChart({ positive, w = 100, h = 36 }) {
    const pts = useRef(Array.from({ length: 30 }, (_, i) => 10 + Math.sin(i * 0.35) * 5 + Math.random() * 3 + (positive ? i * 0.35 : -i * 0.25))).current;
    const max = Math.max(...pts), min = Math.min(...pts);
    const d = pts.map((p, i) => `${i === 0 ? "M" : "L"}${(i / (pts.length - 1)) * w},${h - ((p - min) / (max - min || 1)) * h}`).join(" ");
    const color = positive ? C.green : C.red;
    const id = `mc${positive ? 1 : 0}${w}`;
    return (
        <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`}>
            <defs>
                <linearGradient id={id} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={color} stopOpacity="0.25" />
                    <stop offset="100%" stopColor={color} stopOpacity="0" />
                </linearGradient>
            </defs>
            <path d={d + ` L${w},${h} L0,${h} Z`} fill={`url(#${id})`} />
            <path d={d} fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
    );
}

// ── Markdown Renderer ──
function MD({ text }) {
    if (!text) return null;
    const h = text
        .replace(/^### (.+)$/gm, '<h3 style="color:#6BA5FF;margin:16px 0 6px;font-size:14px;font-weight:700">$1</h3>')
        .replace(/^## (.+)$/gm, '<h2 style="color:#6BA5FF;margin:20px 0 8px;font-size:16px;font-weight:700">$1</h2>')
        .replace(/^# (.+)$/gm, '<h1 style="color:#6BA5FF;margin:22px 0 10px;font-size:18px;font-weight:800">$1</h1>')
        .replace(/\*\*(.+?)\*\*/g, '<strong style="color:#E8ECF1">$1</strong>')
        .replace(/`(.+?)`/g, '<code style="background:rgba(107,165,255,0.1);padding:2px 6px;border-radius:4px;color:#6BA5FF;font-size:12px">$1</code>')
        .replace(/^\- (.+)$/gm, '<div style="padding:3px 0 3px 18px;position:relative"><span style="position:absolute;left:4px;color:#6BA5FF">›</span>$1</div>')
        .replace(/\n/g, "<br/>");
    return <div dangerouslySetInnerHTML={{ __html: h }} style={{ fontSize: "13px", lineHeight: 1.75, color: "rgba(232,236,241,0.8)" }} />;
}

// ── Asset Logo — PNG with branded letter fallback ──
function AssetLogo({ asset, type, size = 48 }) {
    const brandColor = asset.color || C.primary;

    if (type === "forex") {
        const s1 = asset.logo1, s2 = asset.logo2;
        const iconSz = size * 0.72;
        return (
            <div style={{ width: size, height: size, position: "relative", flexShrink: 0 }}>
                {s1 ? <img src={s1} width={iconSz} height={iconSz} style={{ position: "absolute", top: 0, left: 0, borderRadius: "50%", border: "2px solid rgba(15,28,50,0.9)" }} />
                    : <img src={asset.f1} width={iconSz} height={iconSz} style={{ position: "absolute", top: 0, left: 0, borderRadius: "50%", border: "2px solid rgba(15,28,50,0.9)", objectFit: "cover" }} onError={e => { e.target.style.display = "none" }} />}
                {s2 ? <img src={s2} width={iconSz} height={iconSz} style={{ position: "absolute", bottom: 0, right: 0, borderRadius: "50%", border: "2px solid rgba(15,28,50,0.9)" }} />
                    : <img src={asset.f2} width={iconSz} height={iconSz} style={{ position: "absolute", bottom: 0, right: 0, borderRadius: "50%", border: "2px solid rgba(15,28,50,0.9)", objectFit: "cover" }} onError={e => { e.target.style.display = "none" }} />}
            </div>
        );
    }
    if (type === "commodity") {
        return (
            <div style={{ width: size, height: size, borderRadius: "50%", background: "linear-gradient(135deg, rgba(245,183,49,0.12), rgba(245,183,49,0.04))", display: "flex", alignItems: "center", justifyContent: "center", fontSize: size * 0.5, border: "2px solid rgba(245,183,49,0.15)", flexShrink: 0 }}>
                {asset.emoji || asset.sym[0]}
            </div>
        );
    }

    // Stock & Crypto: embedded base64 logo or branded letter fallback
    if (asset.logo) {
        return (
            <div style={{ width: size, height: size, borderRadius: "50%", background: "#fff", display: "flex", alignItems: "center", justifyContent: "center", border: `2px solid ${brandColor}33`, flexShrink: 0, overflow: "hidden", boxShadow: `0 2px 8px ${brandColor}22` }}>
                <img src={asset.logo} width={size * 0.75} height={size * 0.75} style={{ borderRadius: "50%", objectFit: "contain" }} />
            </div>
        );
    }
    return (
        <div style={{ width: size, height: size, borderRadius: "50%", background: `linear-gradient(135deg, ${brandColor}22, ${brandColor}08)`, display: "flex", alignItems: "center", justifyContent: "center", border: `2px solid ${brandColor}33`, flexShrink: 0 }}>
            <span style={{ fontWeight: 800, fontSize: size * 0.38, color: brandColor }}>{asset.sym.replace(/\..+$/, "").slice(0,2)}</span>
        </div>
    );
}

