//  PAGE: PRICING
// ═══════════════════════════════════════════════════════════════════════
function PricingPage({ currentTier, onUpgrade }) {
    const [annual, setAnnual] = useState(false);
    return (
        <div style={{ padding: "32px", overflow: "auto", height: "100%", animation: "fadeIn 0.3s" }}>
            <SectionTitle icon="💳" title="Abonnements Kingest" sub="Choisissez le plan qui correspond à vos ambitions de trading" />
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: "14px", marginBottom: "36px" }}>
                <span style={{ fontSize: "14px", color: !annual ? C.text : C.textDim, fontWeight: 600, fontFamily: font }}>Mensuel</span>
                <button onClick={() => setAnnual(!annual)} style={{
                    width: "52px", height: "28px", borderRadius: "14px", border: "none", cursor: "pointer",
                    background: annual ? C.primary : "rgba(255,255,255,0.1)", position: "relative", transition: "all 0.3s",
                }}>
                    <div style={{ width: "22px", height: "22px", borderRadius: "11px", background: "#fff", position: "absolute", top: "3px", left: annual ? "27px" : "3px", transition: "all 0.3s", boxShadow: "0 2px 6px rgba(0,0,0,0.3)" }} />
                </button>
                <span style={{ fontSize: "14px", color: annual ? C.text : C.textDim, fontWeight: 600, fontFamily: font }}>Annuel</span>
                {annual && <Badge text="−25%" color={C.green} />}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "20px", maxWidth: "1100px", margin: "0 auto" }}>
                {TIERS.map((tier, i) => {
                    const isCurrent = currentTier === tier.id;
                    const price = annual ? (tier.annual / 12).toFixed(2) : tier.price;
                    const isPopular = tier.id === "pro";
                    const isElite = tier.id === "elite";
                    return (
                        <div key={tier.id} style={{
                            borderRadius: "24px", padding: "32px 28px",
                            background: isElite ? `linear-gradient(160deg, ${C.bg}, rgba(236,72,153,0.05))` : isPopular ? `linear-gradient(160deg, ${C.bg}, rgba(99,102,241,0.05))` : C.bg,
                            border: `2px solid ${isCurrent ? tier.color : isPopular ? `${C.primary}40` : C.border}`,
                            position: "relative", transition: "all 0.3s",
                            boxShadow: isPopular ? `0 8px 40px ${C.primaryGlow}` : isElite ? `0 8px 40px ${C.eliteGlow}` : "none",
                            animation: isElite ? "glow 3s infinite" : "none",
                            transform: isPopular ? "scale(1.03)" : "none",
                        }}>
                            {tier.badge && (
                                <div style={{ position: "absolute", top: "-14px", left: "50%", transform: "translateX(-50%)", padding: "5px 20px", borderRadius: "20px", background: `linear-gradient(135deg, ${tier.color}, ${tier.color}CC)`, color: "#fff", fontSize: "10px", fontWeight: 800, letterSpacing: "0.15em", fontFamily: font, boxShadow: `0 4px 12px ${tier.color}40` }}>{tier.badge}</div>
                            )}
                            <div style={{ textAlign: "center", marginBottom: "24px" }}>
                                <div style={{ fontSize: "40px", marginBottom: "8px" }}>{tier.icon}</div>
                                <div style={{ fontSize: "24px", fontWeight: 800, color: tier.color, fontFamily: font }}>{tier.name}</div>
                            </div>
                            <div style={{ textAlign: "center", marginBottom: "28px" }}>
                                {tier.price === 0 ? (
                                    <div style={{ fontSize: "38px", fontWeight: 800, color: C.text, fontFamily: mono }}>0€</div>
                                ) : (
                                    <>
                                        <div style={{ fontSize: "38px", fontWeight: 800, color: C.text, fontFamily: mono }}>{price}€<span style={{ fontSize: "14px", color: C.textDim, fontWeight: 500 }}>/mois</span></div>
                                        {annual && <div style={{ fontSize: "12px", color: C.green, fontWeight: 600, fontFamily: font }}>{tier.annual}€/an · Économisez {((tier.price * 12 - tier.annual)).toFixed(0)}€</div>}
                                    </>
                                )}
                            </div>
                            <div style={{ marginBottom: "28px" }}>
                                {tier.features.map((f, j) => (
                                    <div key={j} style={{ display: "flex", alignItems: "flex-start", gap: "10px", padding: "6px 0" }}>
                                        <span style={{ color: tier.color, fontSize: "14px", flexShrink: 0 }}>✓</span>
                                        <span style={{ fontSize: "12px", color: C.textMid, fontFamily: font, lineHeight: 1.5 }}>{f}</span>
                                    </div>
                                ))}
                            </div>
                            <button onClick={() => !isCurrent && onUpgrade(tier.id)} style={{
                                width: "100%", padding: "14px", borderRadius: "12px", border: isCurrent ? `2px solid ${tier.color}40` : "none",
                                cursor: isCurrent ? "default" : "pointer",
                                background: isCurrent ? "transparent" : `linear-gradient(135deg, ${tier.color}, ${tier.color}CC)`,
                                color: isCurrent ? tier.color : "#fff", fontSize: "14px", fontWeight: 800, fontFamily: font,
                                boxShadow: !isCurrent ? `0 6px 20px ${tier.color}30` : "none",
                                opacity: isCurrent ? 0.7 : 1,
                            }}>{isCurrent ? "Plan actuel" : tier.price === 0 ? "Commencer gratuitement" : `Choisir ${tier.name}`}</button>
                        </div>
                    );
                })}
            </div>
            <div style={{ textAlign: "center", marginTop: "28px", fontSize: "12px", color: C.textDim, fontFamily: font }}>
                Tous les plans incluent l'accès à 10 200+ actifs · Annulation à tout moment · Paiement sécurisé
            </div>
        </div>
    );
}

