//  FEE SUMMARY COMPONENT (for trade modal integration)
// ═══════════════════════════════════════════════════════════════════════
function FeeSummary({ assetType, tier, amount, leverage }) {
    const spread = calcSpread(assetType, tier, amount);
    const overnight = calcOvernight(amount, leverage);
    const net = amount - spread;
    return (
        <div style={{ padding: "14px", borderRadius: "12px", background: "rgba(255,255,255,0.02)", border: `1px solid ${C.border}`, marginBottom: "16px" }}>
            <div style={{ fontSize: "10px", color: C.textDim, textTransform: "uppercase", letterSpacing: "0.1em", fontWeight: 700, marginBottom: "10px", fontFamily: font }}>Récapitulatif des frais</div>
            {[
                { l: "Spread", v: `$${spread.toFixed(2)}`, c: C.textMid, detail: `${(SPREAD_TABLE[assetType]?.[tier === "elite" ? "elite" : tier === "pro" ? "pro" : "standard"] * 100).toFixed(2)}%` },
                { l: "Frais overnight / nuit", v: `$${overnight.toFixed(2)}`, c: C.textMid, detail: `${(getOvernightRate(leverage) * 100).toFixed(3)}%` },
                { l: "Montant net investi", v: `$${net.toFixed(2)}`, c: C.green },
            ].map((r, i) => (
                <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "4px 0" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                        <span style={{ fontSize: "11px", color: C.textDim, fontFamily: font }}>{r.l}</span>
                        {r.detail && <span style={{ fontSize: "9px", color: C.textDim, padding: "1px 6px", borderRadius: "4px", background: "rgba(255,255,255,0.04)", fontFamily: mono }}>{r.detail}</span>}
                    </div>
                    <span style={{ fontSize: "12px", fontWeight: 700, color: r.c, fontFamily: mono }}>{r.v}</span>
                </div>
            ))}
            {tier === "free" && (
                <div style={{ marginTop: "8px", padding: "8px 12px", borderRadius: "8px", background: C.primaryGlow, fontSize: "10px", color: C.primary, fontFamily: font }}>
                    💡 Passez à <strong>Pro</strong> pour réduire vos frais de 50%
                </div>
            )}
        </div>
    );
}

